const COUNT_SUBTASKS = true; // change to false if you only want main/top-level tasks
const EXCLUDE_ARCHIVED = true;

const cleanedTasks = [];
const ownerCounts = {};
const statusCounts = {};

let totalTasks = 0;
let overdueCount = 0;
let completedTasks = 0;

// ---------- Helpers ----------
function isTaskObject(obj) {
  return !!obj && typeof obj === 'object' && (
    obj.id ||
    obj.name ||
    obj.status ||
    obj.date_created ||
    obj.date_updated
  );
}

function getRawTasks() {
  const inputItems = $input.all();

  // Prefer bundled compiled_tasks if present anywhere
  const compiledTaskArrays = inputItems
    .map(item => item?.json?.compiled_tasks)
    .filter(Array.isArray);

  if (compiledTaskArrays.length > 0) {
    return compiledTaskArrays.flat();
  }

  // Otherwise treat each input item as a task
  return inputItems
    .map(item => item?.json)
    .filter(isTaskObject);
}

function dedupeTasks(tasks) {
  const seen = new Map();

  for (const task of tasks) {
    const key =
      task?.id ||
      task?.task_id ||
      task?.custom_id ||
      task?.url ||
      JSON.stringify(task);

    if (!seen.has(key)) {
      seen.set(key, task);
    }
  }

  return [...seen.values()];
}

function toTimestamp(value) {
  if (value === null || value === undefined || value === '') return null;

  if (typeof value === 'number' && Number.isFinite(value)) {
    return value > 1e12 ? value : value * 1000;
  }

  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return null;

    if (/^\d+$/.test(trimmed)) {
      const num = Number(trimmed);
      return num > 1e12 ? num : num * 1000;
    }

    const parsed = Date.parse(trimmed);
    return Number.isNaN(parsed) ? null : parsed;
  }

  return null;
}

function formatDate(value) {
  const ts = toTimestamp(value);
  if (!ts) return null;

  return new Intl.DateTimeFormat('en-PH', {
    timeZone: 'Asia/Manila',
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  }).format(new Date(ts));
}

function normalizeText(text) {
  return String(text ?? '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
}

function toTitleCase(text) {
  const value = String(text ?? '').trim();
  if (!value) return 'Unmapped';

  return value
    .split(/\s+/)
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

function isCompleted(task) {
  const statusType = String(task?.status?.type || '').toLowerCase();
  const statusName = String(task?.status?.status || task?.status || '').toLowerCase();

  return (
    ['done', 'closed', 'complete', 'completed'].includes(statusType) ||
    ['done', 'closed', 'complete', 'completed'].includes(statusName) ||
    !!task?.date_done ||
    !!task?.date_closed
  );
}

function getOwners(task) {
  const assignees = Array.isArray(task?.assignees) ? task.assignees : [];

  const owners = assignees
    .map(a => a?.username || a?.email || a?.id)
    .filter(Boolean);

  return owners.length ? [...new Set(owners)] : ['Unassigned'];
}

function buildDiscussionThread(task) {
  const entries = [];

  const directCommentText =
    normalizeText(task?.comment_text) ||
    normalizeText(
      Array.isArray(task?.comment)
        ? task.comment.map(part => (typeof part?.text === 'string' ? part.text : '')).join('')
        : ''
    );

  if (directCommentText) {
    const author = task?.user?.username || task?.creator?.username || 'Unknown';
    const dateStr = formatDate(task?.date);
    entries.push(`${dateStr ? `[${dateStr}] ` : ''}${author}: ${directCommentText}`);
  }

  if (Array.isArray(task?.comments)) {
    for (const comment of task.comments) {
      const commentText =
        normalizeText(comment?.comment_text) ||
        normalizeText(comment?.text) ||
        normalizeText(
          Array.isArray(comment?.comment)
            ? comment.comment.map(part => (typeof part?.text === 'string' ? part.text : '')).join('')
            : ''
        );

      if (!commentText) continue;

      const author =
        comment?.user?.username ||
        comment?.author?.username ||
        comment?.creator?.username ||
        'Unknown';

      const dateStr = formatDate(
        comment?.date ||
        comment?.date_created ||
        comment?.created_at
      );

      entries.push(`${dateStr ? `[${dateStr}] ` : ''}${author}: ${commentText}`);
    }
  }

  const uniqueEntries = [...new Set(entries)];
  return uniqueEntries.length ? uniqueEntries.join('\n\n') : 'No discussion yet.';
}

// ---------- Main ----------
let allTasks = dedupeTasks(getRawTasks());

if (EXCLUDE_ARCHIVED) {
  allTasks = allTasks.filter(task => !task?.archived);
}

if (!COUNT_SUBTASKS) {
  allTasks = allTasks.filter(task => !task?.parent);
}

const now = Date.now();

for (const task of allTasks) {
  totalTasks++;

  const rawStatusName = task?.status?.status || task?.status || 'unmapped';
  const formattedStatus = toTitleCase(rawStatusName);
  statusCounts[formattedStatus] = (statusCounts[formattedStatus] || 0) + 1;

  const completed = isCompleted(task);
  if (completed) completedTasks++;

  const owners = getOwners(task);
  const taskOwner = owners.join(', ');

  for (const owner of owners) {
    ownerCounts[owner] = (ownerCounts[owner] || 0) + 1;
  }

  const dueTs = toTimestamp(task?.due_date);
  if (dueTs && dueTs < now && !completed) {
    overdueCount++;
  }

  cleanedTasks.push({
    task_id: task?.id || 'N/A',
    task_name: task?.name || 'Unnamed Task',
    task_owner: taskOwner,
    status: formattedStatus,
    is_subtask: !!task?.parent,
    parent_task_id: task?.parent || null,
    top_level_parent: task?.top_level_parent || null,
    due_date: task?.due_date || null,
    due_date_formatted: formatDate(task?.due_date),
    discussion_thread: buildDiscussionThread(task),
    task_url: task?.url || null
  });
}

const completionRate =
  totalTasks === 0 ? 0 : Math.round((completedTasks / totalTasks) * 100);

return [
  {
    json: {
      dashboard_metrics: {
        total_tasks: totalTasks,
        completion_rate: completionRate,
        overdue_tasks: overdueCount,
        tasks_by_owner: ownerCounts,
        tasks_by_status: statusCounts
      },
      sprint_data: cleanedTasks
    }
  }
];

