// 6. Process the AI Report Text (from this node's input)
let html = $input.first().json.output || "";

// Format the Markdown AI text into clean HTML
html = html.replace(/^(\*\*.*?\*\*)$/gm, '<h3 style="color: #334155; font-size: 18px; margin-top: 25px; margin-bottom: 10px;">$1</h3>');
html = html.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
html = html.replace(/`(.*?)`/g, '<code style="background-color: #f1f5f9; padding: 2px 4px; border-radius: 4px; color: #e11d48; font-size: 14px;">$1</code>');
html = html.replace(/^---$/gm, '<hr style="border: 0; height: 2px; background: #e2e8f0; margin: 30px 0;" />');
html = html.replace(/^##\s+(.*)/gm, '<h2 style="color: #1e293b; font-size: 22px; margin-top: 30px; margin-bottom: 15px; border-bottom: 2px solid #3b82f6; padding-bottom: 8px;">$1</h2>');
html = html.replace(/^\*\s+(.*)/gm, '<li style="margin-bottom: 10px;">$1</li>');
html = html.replace(/(<li.*?>.*?<\/li>\n?)+/g, match => `\n<ul style="margin-bottom: 20px; padding-left: 20px;">\n${match}</ul>\n`);

// Catch any unformatted paragraphs (like the Executive Summary) and wrap them
html = html.replace(/^(?!<)(.+)$/gm, '<p style="margin-bottom: 15px;">$1</p>');

// Combine Dashboard + AI Report with global font styling
const finalHtml = `
