const allLists = [];

// 1. Flatten all lists from the folder HTTP requests
for (const item of $input.all()) {
  if (item.json.lists && Array.isArray(item.json.lists)) {
    allLists.push(...item.json.lists);
  }
}

const now = Date.now();

// 2. Filter for strictly ACTIVE sprints (where today falls inside the sprint window)
const activeSprints = allLists.filter(list => {
  // If a list doesn't have start and end dates, it's likely not a sprint, so we skip it
  if (!list.start_date || !list.due_date) return false;

  const startDateMs = parseInt(list.start_date, 10);
  const dueDateMs = parseInt(list.due_date, 10);

  // Keep the list if right now is after the start date AND before the due date
  return now >= startDateMs && now <= dueDateMs;
});

// Stop the workflow gracefully if no active sprints are found
if (activeSprints.length === 0) {
  return []; 
}

// 3. Return each active sprint as a separate item to feed the Loop
return activeSprints.map(sprint => ({ json: sprint }));

function getStartOfWeekManilaMs() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Manila',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(now);
  const map = Object.fromEntries(parts.map(p => [p.type, p.value]));
  const manilaMidnight = new Date(`${map.year}-${map.month}-${map.day}T00:00:00+08:00`);
  const day = manilaMidnight.getDay();
  const daysToMonday = (day + 6) % 7;
  manilaMidnight.setUTCDate(manilaMidnight.getUTCDate() - daysToMonday);
  return manilaMidnight.getTime();
}

const startOfWeekMs = getStartOfWeekManilaMs();

const thisWeekComments = $input.all().flatMap(item => {
  const taskId = item.json.id ?? null;         // from the tasks node
  const comments = Array.isArray(item.json.comments) ? item.json.comments : [];

  return comments
    .filter(comment => {
      const commentMs = Number(comment.date);
      return Number.isFinite(commentMs) && commentMs >= startOfWeekMs;
    })
    .map(comment => ({ ...comment, task_id: taskId }));
});

return thisWeekComments.map(comment => ({ json: comment }));
